### Backend Service Interfaces

```typescript
// packages/sdk/src/types/services.ts

// Auth Service
interface AuthService {
  register(data: RegisterDTO): Promise<{ userId: string; verificationSent: boolean }>;
  login(data: LoginDTO): Promise<TokenPair>;
  refreshToken(refreshToken: string): Promise<TokenPair>;
  verifyEmail(token: string): Promise<void>;
  enableTOTP(userId: string): Promise<{ secret: string; qrCode: string }>;
  verifyTOTP(userId: string, code: string): Promise<boolean>;
  resetPassword(email: string): Promise<void>;
  changePassword(userId: string, data: ChangePasswordDTO): Promise<void>;
}

// Player Service
interface PlayerService {
  getCharacters(userId: string): Promise<Character[]>;
  getInventory(characterId: string, page: number): Promise<PaginatedResult<Item>>;
  transferItem(fromCharId: string, toCharId: string, itemId: string, qty: number): Promise<void>;
  getStatistics(userId: string, period: StatPeriod): Promise<PlayerStats>;
}

// Guild Service
interface GuildService {
  getGuild(guildId: string): Promise<GuildProfile>;
  getMembers(guildId: string, page: number): Promise<PaginatedResult<GuildMember>>;
  searchGuilds(filters: GuildSearchFilters): Promise<PaginatedResult<GuildSummary>>;
  updateSettings(guildId: string, data: GuildSettingsDTO): Promise<void>;
  manageMember(guildId: string, memberId: string, action: MemberAction): Promise<void>;
  getActivityFeed(guildId: string, limit: number): Promise<GuildActivity[]>;
}

// Ranking Service
interface RankingService {
  getRankings(category: RankCategory, page: number, limit: number): Promise<PaginatedResult<RankEntry>>;
  getTopN(category: RankCategory, n: number): Promise<RankEntry[]>;
}

// Marketplace Service
interface MarketplaceService {
  createListing(data: CreateListingDTO): Promise<Listing>;
  createAuction(data: CreateAuctionDTO): Promise<Auction>;
  placeBid(auctionId: string, amount: number): Promise<BidResult>;
  purchase(listingId: string, quantity: number): Promise<PurchaseResult>;
  getPriceHistory(itemId: string, days: number): Promise<PricePoint[]>;
  searchListings(filters: MarketSearchFilters): Promise<PaginatedResult<Listing>>;
}

// Notification Service
interface NotificationService {
  subscribe(userId: string, channels: Channel[]): Promise<void>;
  unsubscribe(userId: string, channels: Channel[]): Promise<void>;
  getRecent(userId: string, limit: number): Promise<Notification[]>;
}
```

### Socket.IO Channel Architecture

```typescript
// apps/api/src/realtime/channels.ts
export enum SocketChannel {
  SERVER_STATUS = 'server-status',
  MARKETPLACE_UPDATES = 'marketplace-updates',
  GUILD_EVENTS = 'guild-events',
  TERRITORY_WAR = 'territory-war',
  PERSONAL_NOTIFICATIONS = 'personal-notifications',
}

// Event payloads
interface ServerStatusEvent {
  serverId: string;
  name: string;
  status: 'online' | 'offline' | 'busy' | 'maintenance';
  playerCount: number;
  maxPlayers: number;
  ping: number;
  maintenanceETA?: string;
}

interface TerritoryUpdateEvent {
  territoryId: string;
  newOwnerId: string | null;
  guildName: string | null;
  guildColor: string;
  captureDate: string;
  isUnderSiege: boolean;
}

interface MarketplaceEvent {
  type: 'listing_created' | 'listing_sold' | 'auction_bid' | 'price_change';
  listingId: string;
  itemId: string;
  price: number;
  timestamp: string;
}
```

### API Gateway Configuration

```typescript
// apps/api/src/gateway/gateway.module.ts
@Module({
  imports: [
    ThrottlerModule.forRoot({
      throttlers: [
        { name: 'authenticated', ttl: 60000, limit: 100 },
        { name: 'unauthenticated', ttl: 60000, limit: 30 },
      ],
    }),
    JwtModule.registerAsync({ /* ... */ }),
  ],
})
export class GatewayModule {}
```

### WebSocket Reconnection Strategy (Client)

```typescript
// packages/sdk/src/realtime/socket-client.ts
export const socketConfig = {
  reconnection: true,
  reconnectionAttempts: 10,
  reconnectionDelay: 1000,        // Start at 1s
  reconnectionDelayMax: 30000,    // Cap at 30s
  factor: 2,                      // Exponential backoff
  timeout: 5000,                  // Connection timeout
  auth: (cb: (data: object) => void) => {
    cb({ token: getAccessToken() });
  },
};

// Fallback to HTTP polling after exhausting reconnection attempts
export function initFallbackPolling(channels: SocketChannel[]) {
  const POLL_INTERVAL = 30_000; // 30 seconds
  const pollableChannels = ['server-status', 'marketplace-updates', 'territory-war'];
  // Only poll channels that support fallback
  return setInterval(() => {
    pollableChannels
      .filter(ch => channels.includes(ch as SocketChannel))
      .forEach(ch => fetchChannelUpdate(ch));
  }, POLL_INTERVAL);
}
```



## Data Models

### Database Schema (Prisma)

```prisma
// packages/database/prisma/schema.prisma

generator client {
  provider = "prisma-client-js"
}

datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

// ─── Authentication & Users ───────────────────────────────────────────

model User {
  id                String    @id @default(uuid())
  email             String    @unique
  passwordHash      String
  username          String    @unique
  emailVerified     Boolean   @default(false)
  verificationToken String?
  verificationExpiry DateTime?
  totpSecret        String?
  totpEnabled       Boolean   @default(false)
  failedLoginAttempts Int     @default(0)
  lockedUntil       DateTime?
  oauthProvider     String?   // 'discord' | 'google'
  oauthId           String?
  role              UserRole  @default(PLAYER)
  createdAt         DateTime  @default(now())
  updatedAt         DateTime  @updatedAt

  characters        Character[]
  notifications     Notification[]
  supportTickets    SupportTicket[]
  refreshTokens     RefreshToken[]
  auditLogs         AuditLog[]      @relation("AuditTarget")
  adminActions      AuditLog[]      @relation("AuditActor")

  @@index([email])
  @@index([oauthProvider, oauthId])
}

enum UserRole {
  PLAYER
  MODERATOR
  GAME_MASTER
  SENIOR_ADMIN
}

model RefreshToken {
  id        String   @id @default(uuid())
  token     String   @unique
  userId    String
  user      User     @relation(fields: [userId], references: [id], onDelete: Cascade)
  expiresAt DateTime
  createdAt DateTime @default(now())

  @@index([userId])
  @@index([token])
}

// ─── Characters & Inventory ───────────────────────────────────────────

model Character {
  id          String        @id @default(uuid())
  userId      String
  user        User          @relation(fields: [userId], references: [id], onDelete: Cascade)
  name        String        @unique
  class       CharacterClass
  level       Int           @default(1)
  experience  BigInt        @default(0)
  currency    Decimal       @default(0) @db.Decimal(15, 2)
  playtime    Int           @default(0) // minutes
  kills       Int           @default(0)
  deaths      Int           @default(0)
  arenaRating Int           @default(0)
  guildId     String?
  guild       Guild?        @relation(fields: [guildId], references: [id])
  guildRank   GuildRank?
  createdAt   DateTime      @default(now())
  updatedAt   DateTime      @updatedAt

  inventory       InventoryItem[]
  equipmentSlots  EquipmentSlot[]
  sellerListings  MarketplaceListing[] @relation("Seller")
  buyerListings   MarketplaceListing[] @relation("Buyer")

  @@index([userId])
  @@index([guildId])
  @@index([level, experience])
  @@index([arenaRating])
}

enum CharacterClass {
  BLADEMASTER
  WIZARD
  PSYCHIC
  VENOMANCER
  BARBARIAN
  CLERIC
  ARCHER
  ASSASSIN
  MYSTIC
  SEEKER
  STORMBRINGER
  DUSKBLADE
}

enum GuildRank {
  LEADER
  OFFICER
  VETERAN
  MEMBER
  RECRUIT
}

model InventoryItem {
  id          String    @id @default(uuid())
  characterId String
  character   Character @relation(fields: [characterId], references: [id], onDelete: Cascade)
  itemId      String
  item        Item      @relation(fields: [itemId], references: [id])
  quantity    Int       @default(1)
  acquiredAt  DateTime  @default(now())

  @@index([characterId])
  @@index([itemId])
}

model Item {
  id          String   @id @default(uuid())
  name        String
  description String?  @db.VarChar(500)
  type        ItemType
  rarity      ItemRarity
  stats       Json?    // Flexible stat block
  iconUrl     String?
  createdAt   DateTime @default(now())

  inventoryItems InventoryItem[]
  listings       MarketplaceListing[]
  priceHistory   PriceHistory[]

  @@index([name])
  @@index([type])
}

enum ItemType {
  WEAPON
  ARMOR
  ACCESSORY
  CONSUMABLE
  MATERIAL
  MOUNT
  FASHION
  MISC
}

enum ItemRarity {
  COMMON
  UNCOMMON
  RARE
  EPIC
  LEGENDARY
  MYTHIC
}

model EquipmentSlot {
  id          String    @id @default(uuid())
  characterId String
  character   Character @relation(fields: [characterId], references: [id], onDelete: Cascade)
  slot        String    // 'head', 'chest', 'weapon', etc.
  itemId      String?

  @@unique([characterId, slot])
}

// ─── Guilds & Territories ─────────────────────────────────────────────

model Guild {
  id            String    @id @default(uuid())
  name          String    @unique
  description   String?   @db.VarChar(500)
  emblemUrl     String?
  leaderId      String
  memberCount   Int       @default(1)
  isRecruiting  Boolean   @default(true)
  minLevel      Int       @default(1)
  createdAt     DateTime  @default(now())
  updatedAt     DateTime  @updatedAt

  members       Character[]
  territories   Territory[]
  activities    GuildActivity[]

  @@index([name])
  @@index([memberCount])
}

model Territory {
  id              String    @id @default(uuid())
  name            String    @unique
  guildId         String?
  guild           Guild?    @relation(fields: [guildId], references: [id])
  guildColor      String?   // Hex color for map display
  captureDate     DateTime?
  defenseStrength Int       @default(0) // 0-100
  isUnderSiege    Boolean   @default(false)
  mapX            Float     // Map coordinate
  mapY            Float     // Map coordinate
  mapWidth        Float     // Territory boundary
  mapHeight       Float     // Territory boundary

  @@index([guildId])
}

model GuildActivity {
  id        String            @id @default(uuid())
  guildId   String
  guild     Guild             @relation(fields: [guildId], references: [id], onDelete: Cascade)
  type      GuildActivityType
  actorName String
  details   Json?
  createdAt DateTime          @default(now())

  @@index([guildId, createdAt])
}

enum GuildActivityType {
  MEMBER_JOIN
  MEMBER_LEAVE
  MEMBER_PROMOTED
  MEMBER_DEMOTED
  MEMBER_KICKED
  TERRITORY_CAPTURED
  TERRITORY_LOST
  WAR_DECLARED
  ANNOUNCEMENT
}

// ─── Marketplace ──────────────────────────────────────────────────────

model MarketplaceListing {
  id            String          @id @default(uuid())
  sellerId      String
  seller        Character       @relation("Seller", fields: [sellerId], references: [id])
  buyerId       String?
  buyer         Character?      @relation("Buyer", fields: [buyerId], references: [id])
  itemId        String
  item          Item            @relation(fields: [itemId], references: [id])
  quantity      Int
  price         Decimal         @db.Decimal(15, 2)
  listingType   ListingType
  status        ListingStatus   @default(ACTIVE)
  // Auction fields
  startingBid   Decimal?        @db.Decimal(15, 2)
  currentBid    Decimal?        @db.Decimal(15, 2)
  minIncrement  Decimal?        @db.Decimal(15, 2)
  highestBidderId String?
  // Timing
  expiresAt     DateTime
  completedAt   DateTime?
  createdAt     DateTime        @default(now())

  bids          AuctionBid[]

  @@index([itemId, status])
  @@index([sellerId])
  @@index([status, expiresAt])
}

enum ListingType {
  FIXED_PRICE
  AUCTION
}

enum ListingStatus {
  ACTIVE
  SOLD
  EXPIRED
  CANCELLED
}

model AuctionBid {
  id        String             @id @default(uuid())
  listingId String
  listing   MarketplaceListing @relation(fields: [listingId], references: [id], onDelete: Cascade)
  bidderId  String
  amount    Decimal            @db.Decimal(15, 2)
  createdAt DateTime           @default(now())

  @@index([listingId, amount])
}

model PriceHistory {
  id        String   @id @default(uuid())
  itemId    String
  item      Item     @relation(fields: [itemId], references: [id])
  price     Decimal  @db.Decimal(15, 2)
  quantity  Int
  soldAt    DateTime @default(now())

  @@index([itemId, soldAt])
}

// ─── Rankings ─────────────────────────────────────────────────────────

model Ranking {
  id        String       @id @default(uuid())
  category  RankCategory
  entityId  String       // Character or Guild ID
  entityName String
  score     BigInt
  tiebreaker BigInt      @default(0)
  rank      Int
  metadata  Json?        // Additional display data
  updatedAt DateTime     @updatedAt

  @@unique([category, entityId])
  @@index([category, rank])
  @@index([category, score, tiebreaker])
}

enum RankCategory {
  TOP_PLAYERS
  TOP_GUILDS
  TOP_PVP
  TOP_ECONOMY
}

// ─── News & Content ───────────────────────────────────────────────────

model NewsArticle {
  id          String       @id @default(uuid())
  title       String
  slug        String       @unique
  excerpt     String       @db.VarChar(200)
  body        String       @db.Text
  category    NewsCategory
  author      String
  imageUrl    String?
  isFeatured  Boolean      @default(false)
  publishedAt DateTime?
  createdAt   DateTime     @default(now())
  updatedAt   DateTime     @updatedAt

  @@index([category, publishedAt])
  @@index([publishedAt])
}

enum NewsCategory {
  PATCH_NOTES
  EVENTS
  COMMUNITY
  ANNOUNCEMENTS
}

// ─── Notifications ────────────────────────────────────────────────────

model Notification {
  id        String           @id @default(uuid())
  userId    String
  user      User             @relation(fields: [userId], references: [id], onDelete: Cascade)
  type      NotificationType
  title     String
  body      String
  data      Json?
  read      Boolean          @default(false)
  createdAt DateTime         @default(now())

  @@index([userId, read, createdAt])
}

enum NotificationType {
  SYSTEM
  MARKETPLACE
  GUILD
  TERRITORY
  ACHIEVEMENT
  SECURITY
}

// ─── Support ──────────────────────────────────────────────────────────

model SupportTicket {
  id          String         @id @default(uuid())
  userId      String?
  user        User?          @relation(fields: [userId], references: [id])
  email       String         // For unauthenticated submissions
  category    SupportCategory
  subject     String         @db.VarChar(150)
  description String         @db.VarChar(2000)
  status      TicketStatus   @default(OPEN)
  reference   String         @unique // Human-readable reference number
  createdAt   DateTime       @default(now())
  updatedAt   DateTime       @updatedAt

  attachments TicketAttachment[]

  @@index([userId, createdAt])
  @@index([status])
  @@index([reference])
}

enum SupportCategory {
  ACCOUNT_ISSUES
  TECHNICAL_PROBLEMS
  BILLING
  BUG_REPORTS
  GENERAL_INQUIRIES
}

enum TicketStatus {
  OPEN
  IN_PROGRESS
  AWAITING_RESPONSE
  RESOLVED
}

model TicketAttachment {
  id       String        @id @default(uuid())
  ticketId String
  ticket   SupportTicket @relation(fields: [ticketId], references: [id], onDelete: Cascade)
  filename String
  url      String
  size     Int           // bytes, max 5MB
}

// ─── Admin & Audit ────────────────────────────────────────────────────

model AuditLog {
  id          String    @id @default(uuid())
  actorId     String
  actor       User      @relation("AuditActor", fields: [actorId], references: [id])
  targetId    String?
  target      User?     @relation("AuditTarget", fields: [targetId], references: [id])
  actionType  String    // 'ban', 'warn', 'promote', 'deploy', etc.
  details     Json?
  createdAt   DateTime  @default(now())

  @@index([actorId, createdAt])
  @@index([targetId])
  @@index([createdAt])
}

// ─── Server Status ────────────────────────────────────────────────────

model GameServer {
  id          String       @id @default(uuid())
  name        String       @unique
  status      ServerStatus @default(OFFLINE)
  playerCount Int          @default(0)
  maxPlayers  Int          @default(5000)
  ping        Int          @default(0) // ms
  maintenanceETA DateTime?
  region      String
  updatedAt   DateTime     @updatedAt

  @@index([status])
}

enum ServerStatus {
  ONLINE
  OFFLINE
  BUSY
  MAINTENANCE
}

// ─── Analytics (Time-Series) ──────────────────────────────────────────

model AnalyticsMetric {
  id        String   @id @default(uuid())
  metric    String   // 'cpu_usage', 'memory_usage', 'active_connections', 'rps'
  value     Float
  metadata  Json?
  timestamp DateTime @default(now())

  @@index([metric, timestamp])
}
```

