  'servers:all': { ttl: 10, type: 'JSON array of ServerStatusEvent' },

  // Session/Auth
  'session:{userId}': { ttl: 900, type: 'Session metadata' },
  'rate_limit:{identifier}': { ttl: 60, type: 'Counter' },
  'account_lock:{userId}': { ttl: 900, type: 'Lock timestamp' },

  // Marketplace
